  crm_cita_id integer,
  canal_origen text DEFAULT 'whatsapp_bot'::text,
  estado text DEFAULT 'confirmada'::text,
  recordatorio_enviado boolean DEFAULT false,
  recordatorio_enviado_at timestamp with time zone,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  PRIMARY KEY (id),
  CONSTRAINT citas_taller_estado_check CHECK ((estado = ANY (ARRAY['confirmada'::text, 'cancelada'::text, 'reagendada'::text, 'completada'::text]))),
  CONSTRAINT "46907_47129_1_not_null" CHECK (id IS NOT NULL),
  CONSTRAINT "46907_47129_2_not_null" CHECK (fecha_cita IS NOT NULL),
  CONSTRAINT "46907_47129_3_not_null" CHECK (hora_cita IS NOT NULL),
  CONSTRAINT "46907_47129_4_not_null" CHECK (taller_solicitado IS NOT NULL),
  CONSTRAINT "46907_47129_5_not_null" CHECK (servicio_solicitado IS NOT NULL),
  CONSTRAINT "46907_47129_7_not_null" CHECK (nombre_cliente IS NOT NULL),
  CONSTRAINT "46907_47129_9_not_null" CHECK (telefono IS NOT NULL),
  CONSTRAINT "46907_47129_10_not_null" CHECK (patente_vehiculo IS NOT NULL)
);
CREATE INDEX idx_citas_fecha ON "nissan-posventa".citas_taller USING btree (fecha_cita);
